    `,achievements:["Trained 500+ students in MERN Stack Development","Developed 20+ live projects for clients across India","Specialized in REST APIs and scalable full-stack architecture"]},{id:"nisha-qureshi-hr-management-counselor",name:"Nisha Qureshi",title:"HR Manager, Career Counselor & Student Success Mentor - JDB Infotech",image:pE,skills:["Human Resource Management","Career Counseling","Student Mentoring","Career Planning","Recruitment & Talent Acquisition","Interview Preparation","Resume Building","Soft Skills Training","Communication Skills Development","Employee Relations","Performance Management","Workforce Planning","Leadership Development","Professional Development","Conflict Resolution","Training & Development","Campus Recruitment","Placement Assistance","Personality Development","Career Assessment","Organizational Behavior","Team Coordination","Client Communication","Counseling & Guidance","Public Speaking","Student Engagement","Workplace Ethics","HR Operations","Talent Management","Corporate Training"],tagline:"Empowering students and professionals with the right career guidance, industry insights, and professional development strategies for long-term success.",experience:"7+ Years of Experience",education:"MBA (Human Resource Management & Organizational Development)",description:`
